+        let gd = GammaDuration::new(2.0, 1.0);
+        let lpdf = gd.log_pdf(1.0);
+        // For Gamma(2,1), f(1) = 1 * exp(-1) = e^-1, so log = -1
+        assert!(approx_eq(lpdf, -1.0, 0.01));
+    }
